class Solution {
public:
    bool doesAliceWin(string s) {
        int n = s.size();
        int cnt[26] = {0};
        for (char c : s) {
            cnt[c - 'a']++;
        }
        int odd = 0, even = 0;
        for (int i = 0; i < 26; i++) {
            if (cnt[i] % 2 == 0) even++;
            else odd++;
        }
        return even == 0 || odd == 1;
    }
};
